\begin{algorithm}
\caption{Feature Creation Process}

\begin{algorithmic}[1]
\State Input: RSSI and SINR signals
\State Output: Normalized PCA features
\For{each signal $S$ (RSSI, SINR)}
 \State Compute moving averages: ma\_2(S), ma\_3(S), ma\_5(S)
 \State Generate sub-sampled signals: S[:,::2], S[:,1::2], S[:,::3], S[:,1::3], S[:,2::3]
 \State Combine all signals (original and derived)
 \For{each signal $S'$ in combined signals}
 \State Apply PCA to $S'$
 \State Retain first 5 PCs of $S'$
 \EndFor
 \State Normalize each PC to the range of the original signal $S$
\EndFor
\State Combine all normalized PCA features
\end{algorithmic}
\end{algorithm}

elements.2412-15312_fig_4431b335:
\begin{algorithm}
\caption{Sample Chunking Algorithm}

\begin{algorithmic}[1]
\Require Number of chunks chunks, current epoch epoch, main samples dictionary samples\_dict\_main.
\State chunks $\gets 10$ \Comment{User-defined number of chunks}
\State start $\gets$ epoch mod chunks
\If{start == 0}
 \State start\_list $\gets$ permutation(range(chunks))
\Else
 \State start $\gets$ start\_list[start]
\EndIf
\State samples\_dict $\gets$ copy(samples\_dict\_main)
\State samples\_dict['train'] $\gets$ samples\_dict['train'][start::chunks,:]
\State Use samples\_dict in the current epoch for the training loop.
\end{algorithmic}
\end{algorithm}

